var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이것이……!","JPN":"これが……！","ENG":"This is it...!","TWN":"這就是……！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리들이 지닌 기사의 긍지다───────────!!","JPN":"我々が持つ騎士の誇りだ───────────！！","ENG":"This is the pride of knights that we bear───────────!!","TWN":"我們擁有的騎士榮耀───────────！！"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"칼질 한 번에… 허신의 몸 반이 날아가 버렸다고……?","JPN":"一撃で……虚神の体半分がなくなった……？","ENG":"One slash... and half of the Hollow God's body is gone...?","TWN":"一刀下去……就斬飛虛神的半個身體了……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"헷, 이거 굉장하잖아?","JPN":"はっ、すごいじゃないか！","ENG":"Heh, that's pretty impressive, isn't it?","TWN":"哼，這不是很厲害嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠, 방어 대형을 갖추어라!","JPN":"ゾディアックナイツ、防衛隊形を整えろ！","ENG":"Zodiac Knights, defensive formations!","TWN":"十二宮騎士團，組成防禦陣形！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전방의 6종 침식체에게 유효한 화력을 낼 수 있는 것은 단장님뿐이다!","JPN":"前方の第6種侵食体に有効なダメージを与えられるのは団長だけだ！","ENG":"Only the Captain can deliver effective firepower against the Category 6 C.O. ahead!","TWN":"只有團長能對前方第6類侵蝕體造成有效殺傷力！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 다음 공격을 준비할 수 있도록 우리가 시간을 버는 거다!","JPN":"団長が次の攻撃を準備できるよう、私たちが時間を稼ぐ！","ENG":"We buy time so the Captain can prepare the next strike!","TWN":"我們要替團長爭取準備下一次攻擊的時間！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그래비티 건, 레디……!","JPN":"グラビティガン、レディー……！","ENG":"Gravity Gun, ready...!","TWN":"重力槍，準備……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마, 그 망원경……?","JPN":"その望遠鏡……","ENG":"Is that the Telescope...?","TWN":"等等，那個望遠鏡……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 제법인데? 이제 제대로 쓰고 있잖아……?","JPN":"もう使いこなせてるの……？　やるじゃない。","ENG":"Huh, not bad. You're finally using it properly now...?","TWN":"哇啊，很厲害嘛？現在不是用得很好嗎……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"오지만디아스, 당신은 부상이 심해요! 녀석의 큰 동작은 제가 막을 게요!","JPN":"オジマンディアス、あなた怪我人なんでしょ！　あいつの大振りは私が止めます！","ENG":"Ozymandias, your injuries are severe! I'll block its major movements!","TWN":"奧茲曼迪亞斯，你的傷勢很嚴重！讓我來抵擋那傢伙的大動作！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까 재장전 시간을 벌어주세요!","JPN":"だから再装填する時間を稼いでください！","ENG":"So buy me time to reload!","TWN":"請你替我爭取重新裝填的時間！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쳇, 꼬맹이 뒤치다꺼리는 별로 마음에 안 들지만……!","JPN":"まったく、おこちゃまの世話とか、あまり気乗りしないけど……！","ENG":"Tch, babysitting a kid isn't my favorite job...!","TWN":"嘖，照顧小鬼實在不怎麼對我胃口……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"맡겨두라고, 챔피언!","JPN":"任せなさい、チャンピオン！","ENG":"Leave it to me, champion!","TWN":"交給我吧，冠軍！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"거기, 변호사! 뭔가 할 셈이지?","JPN":"そこの弁護士！　なんかやるつもりなんだろ？","ENG":"Hey, lawyer! You planning to do something?","TWN":"喂，律師！你打算做什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"걸리적 거리는 건, 나한테 맡기라고! 길 정도는 열어 줄 테니까……!","JPN":"邪魔なものがあったら言って！　道を開けるぐらいはしてやるから……！","ENG":"Leave the nuisances to me! I'll open a path...!","TWN":"礙事的傢伙就交給我！我會替你們開路……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그래? 그렇다면 허리를 조금 숙여줬으면 좋겠군.","JPN":"そうか？　なら少し屈んでくれるか。","ENG":"Oh? Then I'd like you to bend at the waist a little.","TWN":"是嗎？那就麻煩你稍微彎一下腰了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L37_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"허리라고? 이렇게……","JPN":"屈む？　こうか……","ENG":"My waist? Like this–","TWN":"彎腰？這樣嗎……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"커헉!?","JPN":"がはっ！？","ENG":"Guh?!","TWN":"咳啊！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L40_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이 자식, 날 발판으로 쓸 셈이었냐!","JPN":"てめぇっ、私を踏み台にしやがったな！","ENG":"Hey, you jerk! Were you planning to use me as a stepping stone?!","TWN":"你這混帳，打算把我當踏板嗎！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"즉결심판! 그 죄를 묻겠다……!!","JPN":"即決審判！　その罪を問う……！！","ENG":"Justice is served! You will answer for your crimes...!!","TWN":"即決審判！我要追究你的罪行……！！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오지만디아스, 지금입니다!","JPN":"オジマンディアス、今です！","ENG":"Ozymandias, now!","TWN":"奧茲曼迪亞斯，就是現在！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"크윽, 부상자한테 너무 많은 걸 바라는 거 아니야?","JPN":"くっ、怪我人に色々頼みすぎじゃないの？","ENG":"Ghk, aren't you asking too much of someone who's injured?","TWN":"咳，你對傷患要求也太多了吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L2_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아가 약한 소리를 다 하네?","JPN":"ジュリアが弱音を吐くだなんて。","ENG":"Julia's sounding awfully weak today.","TWN":"居然聽到茱莉亞在示弱？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"설마, 이 정도로 지친 거야? 너도 한 물 갔구나?","JPN":"まさかこれぐらいでへばっちゃったの？　あなたももう年ね。","ENG":"What, already tired at this level? Guess you're past your prime.","TWN":"怎麼？你該不會這樣就累了吧？你也老了啊？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊、哈啊、哈啊……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너, 시끄럽거든? 가서 애송이 기사단이나 봐주지 그래?","JPN":"うるさいわね。騎士団のガキどもの世話でもしたらどう？","ENG":"Shut it. Why don't you go babysit the rookie knights?","TWN":"你很吵耶？你要不要去照顧那些菜鳥騎士團？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"애송이라고? 글쎄?","JPN":"ガキ？　どうかしら？","ENG":"Rookies? I wonder.","TWN":"菜鳥？是嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"내 눈에는 이제 다들 한 사람 몫은 하는 것 같은데?","JPN":"私にはもうみんな一人前に見えるけど？","ENG":"From where I stand, they all seem to be pulling their weight now.","TWN":"在我看來，大家現在都已經能獨當一面了呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"부상자들은 결계 안쪽으로 오세요!","JPN":"負傷者は結界の内側に！","ENG":"Injured personnel, move inside the barrier!","TWN":"傷者請進入結界內！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽이에요! 다치신 분들은 제가 낫게 해드릴 테니까……!","JPN":"こっちです！　怪我をした方は私が治療しますから……！","ENG":"Over here! I'll heal anyone who's hurt...!","TWN":"來這邊！我會替受傷的人治療……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경! 후방이 밀리면 안 돼요!","JPN":"リブ卿！　後方が押されてはいけません！","ENG":"Dame Liv! We can't let the rear line collapse!","TWN":"莉芙卿！後方不能被突破！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"나도 알고 있다구! 한솔아!","JPN":"そんなのわかってるよ！　イチロウ！","ENG":"I know! Hansol!","TWN":"我知道啦！楊瀚！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"특수탄 전부 때려 박아! 하위 침식체는 우리가 맡는다!","JPN":"特殊弾を全部ぶち込め！　下位侵食体は我々が倒す！","ENG":"Load all the special rounds! We'll handle the low-level ones!","TWN":"特殊彈全部發射！低階侵蝕體交給我們！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"카운터 분들이 조금이라도 체력을 회복할 수 있게끔, 시간을 버는 거다……!","JPN":"カウンターの皆さんが少しでも体力を回復できるように、時間を稼ぐんだ……！","ENG":"Buy time so the Counters can recover even a little...!","TWN":"哪怕只讓制裁者們恢復一點體力，我們也要爭取時間……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 하하…….","JPN":"は、はは……","ENG":"Ha, haha...","TWN":"哈、哈哈……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"미쳤어. 다들 제정신이 아니야…….","JPN":"狂ってる。みんな頭がおかしくなったのよ……","ENG":"This is insane. None of them are in their right minds...","TWN":"瘋了，大家都不正常了……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"서로가 서로를 지켜주며 싸우고 있어…….","JPN":"お互いがお互いを守りながら戦ってる……","ENG":"They're protecting each other as they fight...","TWN":"彼此守護、彼此掩護戰鬥……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"허신 토벌을 시작한 지, 한 시간이 다 되어가는데, 이정도까지 싸울 수 있다니…….","JPN":"虚神討伐を開始してほぼ1時間が経つのに、ここまで戦えるだなんて……","ENG":"It's been almost an hour since we started subjugating the Hollow God, and we're still holding on...","TWN":"討伐虛神已經快一個小時了，竟然能撐到這種程度……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 이렇게까지 몰아붙이는데도 녀석은 건재해…….","JPN":"でも、これほど追い詰めてもなお、やつはまだピンピンしてる……","ENG":"But even after pushing it this far, it's still standing...","TWN":"可是就算我們逼到這樣，那傢伙仍然毫髮無傷……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무리 육체를 파괴한다고 해도, 곧바로 재생해 버리니까…….","JPN":"どんなに肉体を破壊しても、すぐ再生してしまうから……","ENG":"No matter how much we destroy its body, it regenerates immediately...","TWN":"不管破壞肉體多少次，馬上就會再生……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"법학부장이 말한 <color=#ffd34c>해결책</color>이 오지 않으면 결국에는……","JPN":"法学部長が言ってた<color=#ffd34c>解決策</color>とやらが来ないと、結局は……","ENG":"If the <color=#ffd34c>solution</color> the Dean of Law mentioned doesn't arrive, then eventually–","TWN":"要是法學院院長說的<color=#ffd34c>解決方案</color>再不出現，最後還是……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"컥!?","JPN":"けっ！？","ENG":"Kuh?!","TWN":"咳！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_FIRE_SMALL_09"},{"id":"L39_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"말조심해야지, 우리 멍멍이.","JPN":"言葉には気をつけないと、ワンちゃん。","ENG":"Watch your mouth, Puppy.","TWN":"說話小心點啊，我們狗狗。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그 전장은 듣는 귀가 너무 많거든~","JPN":"そっちの戦場には耳が多すぎるからね～","ENG":"There are far too many ears listening on that battlefield.","TWN":"戰場上有太多雙耳朵在聽了～"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어, 언니? 이건……?","JPN":"ね、姉さん？　これは……？","ENG":"A-Agnes? Was that...?","TWN":"姐、姐姐？這是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"응, 환각탄이야. 아무래도 우리 멍멍이가 생각이 너무 많은 것 같아서.","JPN":"うん、幻覚弾よ。ワンちゃんが考えすぎちゃってるみたいだったから。","ENG":"Yeah, a hallucination round. You seemed to be overthinking things.","TWN":"嗯，是幻覺彈。看來我們家狗狗想太多了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"달이라도 보면서, 머리를 좀 비우면 어떨까?","JPN":"月でも見て、頭を冷やしたらどうかしら？","ENG":"Why don't you clear your head a bit and look at the moon?","TWN":"不如看看月亮，讓腦袋放空一下？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"달……?","JPN":"月……？","ENG":"The moon...?","TWN":"月亮……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_OMEN_CUTIN_NULL","text":{"KOREA":"<color=#ff3636>크르륵, 크르르르르르르르르……!</color>","JPN":"<color=#ff3636>グルル、グルルルルルルルル……！</color>","ENG":"<color=#ff3636>Krrgh, grrrrrrrrrrr...!</color>","TWN":"<color=#ff3636>咕嚕……咕嚕嚕嚕嚕嚕嚕嚕……！</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_OMEN_CUTIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_39"},{"id":"L50_1","type":"dialog","speaker":"LUCIA_OMEN_CUTIN_NULL","text":{"KOREA":"<color=#ff3636>크와아아아아아아아아─────────────!!</color>","JPN":"<color=#ff3636>くわああああああああ─────────────！！</color>","ENG":"<color=#ff3636>KRAAAAAAAA─────────────!!</color>","TWN":"<color=#ff3636>咕哇啊啊啊啊啊─────────────！！</color>"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_OMEN_CUTIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊、哈啊、哈啊……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL_06"},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"크윽, 이제 무구 개방도 한계에 다다랐나……?","JPN":"くっ、武具開放もそろそろ限界か……？","ENG":"Kgh, has even my armament unleashing reached its limit already...?","TWN":"咳，武具解放也快到極限了嗎……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮으십니까, 단장님?","JPN":"大丈夫ですか、団長！","ENG":"Are you all right, Captain?","TWN":"你還好嗎，團長？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"나는 괜찮아, 하지만…….","JPN":"私はいい。だが……","ENG":"I'm fine, but...","TWN":"我沒事，但是……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다들 지쳤어요. 전선을 물려야 합니다.","JPN":"皆疲れています。前線を後退させるべきかと。","ENG":"Everyone's exhausted. We need to pull back.","TWN":"大家都已經疲憊不堪了，前線得往後退才行。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"안 돼. 여기서 포기하면 더는 돌이킬 수 없게 될 거다.","JPN":"駄目だ。ここで諦めたら取り返しがつかなくなる。","ENG":"No. If we give up here, there will be no turning back.","TWN":"不行。在這裡放棄的話，就再也無法回頭了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지만……!","JPN":"ですが……！","ENG":"But...!","TWN":"可、可是……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"부단장, 이 전장에서 우리는 선봉을 맡았어.","JPN":"副団長、この戦場で私たちは先鋒を任されている。","ENG":"Deputy, we took the vanguard in this battle.","TWN":"副團長，在這個戰場上我們負責的是先鋒。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리가 쓰러진다면, 틀림없이 다들 무너지고 말겠지.","JPN":"私たちが倒れたら、きっと皆崩れてしまう。","ENG":"If we fall, everyone else will collapse as well.","TWN":"如果我們倒下了，其他人一定也會跟著崩潰。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_CHARLOTTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그러니까 나는…….","JPN":"だから私は……","ENG":"So I...","TWN":"所以我……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"우리는…….","JPN":"私たちは……","ENG":"We...","TWN":"我們……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"영지가 무척 소란스럽군요.","JPN":"領地が騒がしいですわね。","ENG":"The estate is quite noisy.","TWN":"領地似乎騷動不安呢。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"동결된 시간 속에서 당신이 이 말을 들을 일은 없겠지만…….","JPN":"凍結した時間の中であなたにこの声が届くことはないでしょうけれど……","ENG":"You won't be able to hear this within frozen time, but...","TWN":"雖然在被凍結的時間中，你不會聽見這些話……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"지금까지 잘 버텨 주었습니다, 슈발리에 경.","JPN":"今までよく耐えてくれました、シュヴァリエ卿。","ENG":"You've held out well, Dame Chevalier.","TWN":"一直以來都辛苦你了，艾斯特洛索卿。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"학회장으로서 그대와 이 전장에서 싸운 모든 이들에게 경의를 표하죠.","JPN":"学会長として、あなたと、この戦場で戦ったすべての者に敬意を表します。","ENG":"As President, I pay my respects to you and all who fought on this battlefield.","TWN":"身為學會長，我向你，以及在這個戰場上奮戰的所有人致上敬意。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And yet...","TWN":"然後……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"역시 신성을 가진 침식체…….","JPN":"やはり神聖を持つ侵食体……","ENG":"A C.O. bearing Divinity...","TWN":"果然是擁有神性的侵蝕體……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"멈춰버린 시간 속에서도, 그 육신은 계속해서 재생을 반복하는군.","JPN":"止まった時間の中でもその肉身は再生を繰り返すのね。","ENG":"Even within stopped time, its flesh continues to regenerate.","TWN":"即使在停滯的時間中，那副肉體仍在不斷再生。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"나조차도 이것을 토벌하는 것은 불가능하겠지.","JPN":"私ですらこれを討伐することはできない。","ENG":"Even I would be unable to subjugate it.","TWN":"就連我，恐怕也無法討伐它吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그렇다면…….","JPN":"ならば……","ENG":"In that case...","TWN":"既然如此……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 처리하세요.","JPN":"エデル、始末しなさい。","ENG":"Edel, proceed.","TWN":"艾瑟兒，處理掉。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네, 기꺼이요. 나의 레지나님.","JPN":"はい、喜んで。我々のレジーナ様。","ENG":"Yes, with pleasure, our Regina.","TWN":"是，樂意之至。我的蕾佳娜大人。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};